export const amsterdamSpots = [
  { id:'amsterdam-begijnhof', name:'Begijnhof', city:'Amsterdam', country:'Netherlands', shortDesc:'Medieval almshouse courtyard behind an unmarked door on Spui', fullDesc:'One of Amsterdam\'s oldest inner courts, dating to the 14th century. A ring of historic almshouses encloses a garden and a clandestine English Reformed church. The cobbled courtyard feels entirely removed from the city noise outside.', whyHidden:'Entrance is an unmarked wooden gate on Spui square — no sign, no ticket booth. Most visitors walk straight past it.', bestTime:'Weekday mornings before 10am', howToGet:'Walk to Spui square; wooden gate is set into the wall on the north side.', whatToAvoid:'Weekday afternoons when tour groups pass through', hiddennessScore:5, category:'Architecture / Landmark', interests:['monuments','photography'], lat:52.3698, lng:4.8892, address:'Begijnhof, 1012 WX Amsterdam', entryPrice:'Free', photo:'1536697086436-c3c04c8e0d8a' },
  { id:'amsterdam-electric-ladyland', name:'Electric Ladyland', city:'Amsterdam', country:'Netherlands', shortDesc:'World\'s first fluorescent art museum inside a Jordaan canal house', fullDesc:'Six floors of a canal house packed with fluorescent minerals, psychedelic art and UV installations. Founded by American artist Nick Padalino in 1997, it remains one of the most genuinely strange cultural spaces in Europe. Visitors descend into a cave of glowing rocks and blacklit sculptures.', whyHidden:'No exterior signage; looks like a private residence. The niche subject keeps it off every mainstream guide.', bestTime:'Any time — the darkness makes it time-independent', howToGet:'Walk north along Prinsengracht from Leidseplein; look for number 5 on Tweede Leliedwarsstraat.', whatToAvoid:'Closed Monday and Tuesday', hiddennessScore:9, category:'Gallery / Art', interests:['art','unusual'], lat:52.3771, lng:4.8838, address:'Tweede Leliedwarsstraat 5, Amsterdam', entryPrice:'€5', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-wynand-fockink', name:'Wynand Fockink Proeflokaal', city:'Amsterdam', country:'Netherlands', shortDesc:'17th-century jenever tasting room in a Dam Square alley since 1679', fullDesc:'A tiny standing-room jenever distillery and tasting house operating since 1679, tucked into the Pijlsteeg alley behind the Krasnapolsky hotel. Bartenders pour glasses so full you must drink the first sip without lifting the glass — a house tradition unchanged for centuries.', whyHidden:'The Pijlsteeg alley entrance is easy to miss and the exterior gives nothing away. Tourists walk to the Heineken Experience instead.', bestTime:'Weekday afternoons 3–6pm when locals finish work', howToGet:'Enter Pijlsteeg alley directly behind the NH Krasnapolsky hotel on Dam square.', whatToAvoid:'Evenings and Saturday nights when it gets packed with tourists', hiddennessScore:7, category:'Bar / Nightlife', interests:['food','nightlife'], lat:52.3726, lng:4.8984, address:'Pijlsteeg 31, 1012 HH Amsterdam', entryPrice:'Free entry', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-museum-het-schip', name:'Museum Het Schip', city:'Amsterdam', country:'Netherlands', shortDesc:'Entire Amsterdam School housing block turned living museum', fullDesc:'A breathtaking 1921 social housing complex by Michel de Klerk, one of the finest examples of the Amsterdam School of architecture. The building contains a post office, workers\' homes and a museum — all with original curved brickwork and decorative ironwork intact. Like walking into a fairy-tale brick castle built for the working class.', whyHidden:'Located in the Spaarndammerbuurt, a residential western neighbourhood rarely visited. Almost never appears on guided tours despite being extraordinary.', bestTime:'Weekday mornings for quiet corridors', howToGet:'Tram 12 to Spaarndammerstraat; 5-minute walk north.', whatToAvoid:'Closed Mondays', hiddennessScore:8, category:'Museum / History', interests:['museums','art','monuments'], lat:52.3898, lng:4.8741, address:'Spaarndammerplantsoen 140, Amsterdam', entryPrice:'€16', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-katten-kabinet', name:'Katten Kabinet', city:'Amsterdam', country:'Netherlands', shortDesc:'Picasso and Toulouse-Lautrec cat art inside a Golden Age canal house', fullDesc:'A 17th-century canal house at Herengracht 497 devoted entirely to artworks featuring cats — Picasso, Toulouse-Lautrec, Steinlen and others. The building has original painted ceilings, period furniture, and actual resident cats wandering the rooms. One of the strangest and most enjoyable museums in Amsterdam.', whyHidden:'The niche subject keeps mass audiences away. Most visitors to Herengracht photograph the exterior and never look for the entrance.', bestTime:'Quiet weekday afternoons', howToGet:'Walk south along Herengracht from Leidseplein to number 497.', whatToAvoid:'Closed Monday', hiddennessScore:8, category:'Gallery / Art', interests:['art','museums'], lat:52.3644, lng:4.8889, address:'Herengracht 497, Amsterdam', entryPrice:'€10', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-oudemanhuispoort', name:'Oudemanhuispoort Book Market', city:'Amsterdam', country:'Netherlands', shortDesc:'18th-century covered passageway lined with secondhand booksellers', fullDesc:'A covered arcade connecting two canal streets, lined with stalls selling secondhand books, antique maps and prints. The passageway has operated as a book market since the 18th century and belongs to the University of Amsterdam, which flanks it on both sides. A genuinely functional antiquarian market.', whyHidden:'No signs point you here; the arched entrances are subtle and rarely appear on tourist maps.', bestTime:'Monday to Friday during university term', howToGet:'Enter through the arch on Oudezijds Achterburgwal 231 or Kloveniersburgwal 22.', whatToAvoid:'Closed weekends and during summer holidays', hiddennessScore:7, category:'Market / Street Food', interests:['markets','photography'], lat:52.3698, lng:4.8979, address:'Oudemanhuispoort, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-de-ceuvel', name:'De Ceuvel', city:'Amsterdam', country:'Netherlands', shortDesc:'Reclaimed shipyard creative campus and café in Amsterdam Noord', fullDesc:'A cluster of repurposed houseboats and experimental pavilions on a former polluted shipyard in Amsterdam Noord. The site uses phytoremediation to clean contaminated soil while operating as a café, studios and living urban experiment. The most forward-thinking space in Amsterdam.', whyHidden:'Located 10 minutes\' walk from the NDSM ferry landing in Noord, itself requiring the free ferry from Centraal. Just enough friction to keep it authentic.', bestTime:'Friday afternoons for the café terrace; warm summer evenings', howToGet:'Free NDSM ferry from behind Centraal Station, walk 10 minutes north along Korte Papaverweg.', whatToAvoid:'Café closed in winter on weekends; check schedule online', hiddennessScore:9, category:'Neighbourhood / District', interests:['art','photography'], lat:52.3928, lng:4.9063, address:'Korte Papaverweg 4, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-pipe-museum', name:'Amsterdam Pipe Museum', city:'Amsterdam', country:'Netherlands', shortDesc:'Four floors of pipes and smoking culture in a 17th-century canal house', fullDesc:'A four-storey Golden Age canal house on Prinsengracht dedicated entirely to pipes and smoking culture from antiquity to the present. The ethnographic collection spans six continents — pre-Columbian clay pipes, Ottoman nargiles, Dutch 17th-century clay pipes. Genuinely fascinating and completely off the tourist radar.', whyHidden:'The most niche museum in Amsterdam. Subject matter ensures it stays quiet despite being one of the best ethnographic collections in the city.', bestTime:'Any weekday afternoon', howToGet:'Walk south along Prinsengracht from Leidseplein to number 488.', whatToAvoid:'Closed Monday', hiddennessScore:9, category:'Museum / History', interests:['museums','unusual'], lat:52.3644, lng:4.8885, address:'Prinsengracht 488, Amsterdam', entryPrice:'€8', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-ndsm-wharf', name:'NDSM Wharf', city:'Amsterdam', country:'Netherlands', shortDesc:'Former ocean-liner dry dock turned vast arts district in Noord', fullDesc:'A former shipyard covering over 100,000 square metres in Amsterdam Noord, converted into a sprawling arts campus with studios, a flea market, a graffiti hall and regular festivals. The scale of the original dry-dock buildings is extraordinary — nothing else in Amsterdam compares for raw industrial grandeur.', whyHidden:'Requires the free ferry from Centraal Station every 30 minutes — just enough friction to filter out casual tourists.', bestTime:'Sunday flea market; summer festival season', howToGet:'Free NDSM ferry from behind Centraal Station, pier behind the Doubletree hotel.', whatToAvoid:'Weekday mornings when few venues are open', hiddennessScore:6, category:'Underground / Subculture', interests:['art','markets','nightlife'], lat:52.4046, lng:4.8975, address:'NDSM-plein, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-brouwerij-ij', name:"Brouwerij 't IJ", city:'Amsterdam', country:'Netherlands', shortDesc:'Craft brewery operating since 1985 inside a working 18th-century windmill', fullDesc:'Amsterdam\'s best-loved local brewery inside the De Gooyer windmill on the Funenkade. The tasting room is tiny, the beers excellent, and the combination of a functioning windmill and craft ale makes for one of the most photogenic drinking experiences in the city. Popular with locals, almost never marketed to tourists.', whyHidden:'The Funenkade location is outside the main canal ring. Locals know it; the city\'s tourist industry focuses on the Heineken Experience instead.', bestTime:'Weekday afternoons 2–8pm', howToGet:'Tram 7 or 14 to Funenkade stop; or a 20-minute walk from Rembrandtplein.', whatToAvoid:'Closes at 8pm; weekend afternoons get busy', hiddennessScore:6, category:'Bar / Nightlife', interests:['food','nightlife'], lat:52.3664, lng:4.9213, address:'Funenkade 7, Amsterdam', entryPrice:'Free entry', photo:'1571467512417-22f9ae5d7b50' },
  { id:'amsterdam-hortus-botanicus', name:'Hortus Botanicus', city:'Amsterdam', country:'Netherlands', shortDesc:'One of the world\'s oldest botanical gardens, founded 1638', fullDesc:'Established as a medicinal herb garden in 1638, the Hortus contains over 6,000 plant species including a 300-year-old Eastern Cape cycad — one of the oldest potted plants on Earth. A three-climate greenhouse holds tropical, subtropical and desert zones. The palm house in winter is extraordinary.', whyHidden:'Overshadowed by the Rijksmuseum and Van Gogh. The tropical greenhouse in winter is one of the best experiences in Amsterdam.', bestTime:'Midweek mornings; remarkable in all seasons', howToGet:'Walk 5 minutes east from Waterlooplein tram stop along Plantage Middenlaan.', whatToAvoid:'School trips Tuesday and Thursday mornings', hiddennessScore:5, category:'Park / Green Space', interests:['hiking','relaxation','photography'], lat:52.3662, lng:4.9084, address:'Plantage Middenlaan 2A, Amsterdam', entryPrice:'€13', photo:'1464822759023-fed622ff2c3b' },
  { id:'amsterdam-foam-museum', name:'Foam Photography Museum', city:'Amsterdam', country:'Netherlands', shortDesc:'World-class photography exhibitions in a narrow Keizersgracht canal house', fullDesc:'A 17th-century canal house on Keizersgracht housing one of Europe\'s finest photography museums. Four interconnected floors present rotating exhibitions of international contemporary photographers alongside archival shows. The programme rivals any major gallery at a fraction of the footfall.', whyHidden:'Photography museums don\'t attract mass audiences. This one consistently runs shows equal to Tate Modern with almost no queues.', bestTime:'Thursday evenings (late opening until 9pm)', howToGet:'Walk south along Keizersgracht from Leidseplein to number 609.', whatToAvoid:'Closed on exhibition changeover days — check the website', hiddennessScore:6, category:'Gallery / Art', interests:['art','photography'], lat:52.3638, lng:4.8985, address:'Keizersgracht 609, Amsterdam', entryPrice:'€13', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-noordermarkt', name:'Noordermarkt Organic Market', city:'Amsterdam', country:'Netherlands', shortDesc:'Best organic farmers\' market around a 17th-century Jordaan church', fullDesc:'Every Saturday morning the square around the Noorderkerk fills with the city\'s best organic market — local cheese, artisan bread, heritage vegetables and cut flowers. The adjacent Monday flea market attracts more tourist press; the Saturday organic market remains entirely local.', whyHidden:'The adjacent Jordaan flea market absorbs tourist attention. Locals quietly shop here every Saturday morning.', bestTime:'Saturday 9am–3pm; arrive before noon for the best stalls', howToGet:'Tram 5 or 13 to Haarlemmerstraat, walk north into the Jordaan.', whatToAvoid:'After midday the best produce stalls are often sold out', hiddennessScore:5, category:'Market / Street Food', interests:['food','markets'], lat:52.3786, lng:4.8821, address:'Noordermarkt, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-ons-lieve-heer', name:"Ons' Lieve Heer op Solder", city:'Amsterdam', country:'Netherlands', shortDesc:'Secret Catholic church hidden inside three connected canal houses (1663)', fullDesc:'Three interconnected 17th-century canal houses conceal a complete Catholic church on their upper floors, built in 1663 when public Catholic worship was banned. The church — baroque altar, pipe organ, hidden sacristy — is preserved exactly as built. One of the most extraordinary concealed spaces in Europe.', whyHidden:'The exterior looks like three ordinary canal houses. Only a small plaque on Oudezijds Voorburgwal indicates what lies inside.', bestTime:'Opening hour (10am) before school groups arrive', howToGet:'Walk north from Centraal along Oudezijds Voorburgwal to number 38.', whatToAvoid:'Weekday mornings during school season; closed Monday', hiddennessScore:5, category:'Spiritual / Ritual', interests:['museums','monuments','photography'], lat:52.3749, lng:4.8963, address:'Oudezijds Voorburgwal 38, Amsterdam', entryPrice:'€15', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-eye-film-institute', name:'EYE Film Institute', city:'Amsterdam', country:'Netherlands', shortDesc:'Deconstructivist film museum with the best view of Amsterdam\'s skyline', fullDesc:'A dramatic white angular building by Delugan Meissl architects on the north bank of the IJ, housing a cinema archive, four screens and a bar-restaurant terrace with a spectacular view of Amsterdam\'s skyline across the water. The ground floor and terrace are free to enter.', whyHidden:'Requires the free ferry from Centraal — many visitors assume Noord is industrial. Those who cross find one of the best buildings in the city.', bestTime:'Evening screenings; the terrace bar at sunset', howToGet:'Free Buiksloterweg ferry from behind Centraal Station, 2-minute crossing.', whatToAvoid:'Exhibition rooms have an entry charge; ground floor and terrace are free', hiddennessScore:5, category:'Gallery / Art', interests:['art','photography'], lat:52.3842, lng:4.9006, address:'IJpromenade 1, Amsterdam', entryPrice:'Free / varies', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-de-hallen', name:'De Hallen', city:'Amsterdam', country:'Netherlands', shortDesc:'1902 tram depot turned food hall, cinema and weekend textile market', fullDesc:'A beautiful red-brick tram depot in Oud-West converted into a cultural complex housing a food hall, two cinema screens, a library, boutique hotel and a Saturday textile market. The original depot structure — high vaulted ceilings, exposed brickwork — is entirely preserved.', whyHidden:'In Oud-West, a neighbourhood most tourists skip. The conversion is understated and the complex easy to miss on Hannie Dankbaarpassage.', bestTime:'Weekend food hall from 11am; cinema any evening', howToGet:'Tram 1, 7 or 17 to Kinkerstraat; De Hallen is on Hannie Dankbaarpassage.', whatToAvoid:'Food hall gets busy Saturday lunchtimes', hiddennessScore:5, category:'Market / Street Food', interests:['food','markets','art'], lat:52.3587, lng:4.8684, address:'Hannie Dankbaarpassage 33, Amsterdam', entryPrice:'Free entry', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-hofje-van-brienen', name:'Hofje van Brienen', city:'Amsterdam', country:'Netherlands', shortDesc:'1804 almshouse courtyard garden hidden behind a Prinsengracht door', fullDesc:'A private courtyard founded in 1804 as an almshouse for elderly women, accessible through a door in the wall of Prinsengracht. The courtyard garden is immaculately kept with gravel paths, a sundial and a central pump. One of the most tranquil spaces in the Jordaan.', whyHidden:'A simple wooden door in a canal-house facade with no marking. Even many Amsterdammers have never entered.', bestTime:'Weekday mornings in spring and summer', howToGet:'Walk along Prinsengracht north of Westerkerk; look for the wooden door at numbers 89–133.', whatToAvoid:'Closed after 6pm; be respectful of the residents', hiddennessScore:8, category:'Park / Green Space', interests:['relaxation','photography'], lat:52.3770, lng:4.8836, address:'Prinsengracht 89-133, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-stadsarchief', name:'Stadsarchief Amsterdam', city:'Amsterdam', country:'Netherlands', shortDesc:'Art Nouveau banking palace housing the city archive — free, spectacular', fullDesc:'Amsterdam\'s city archive in the extraordinary 1923 De Bazel building, originally built for the Netherlands Trading Society. The public reading rooms and basement galleries are free and often display excellent exhibitions using maps, documents and photographs from 800 years of Amsterdam history.', whyHidden:'Few tourists think to visit a city archive. The building alone — stained glass, marble floors, decorative brickwork — justifies the visit.', bestTime:'Any weekday during opening hours', howToGet:'Walk from Waterlooplein tram stop; the building is on Vijzelstraat 32.', whatToAvoid:'Closed weekends and public holidays', hiddennessScore:7, category:'Museum / History', interests:['museums','monuments','photography'], lat:52.3623, lng:4.8950, address:'Vijzelstraat 32, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-tassenmuseum', name:'Tassenmuseum Hendrikje', city:'Amsterdam', country:'Netherlands', shortDesc:'Five centuries of bags and purses in a Golden Age canal house', fullDesc:'A canal house at Herengracht 573 housing the world\'s largest collection of bags and purses, spanning five centuries. Medieval pouches, 18th-century reticules, Art Deco evening bags and contemporary designer pieces. The building has original painted ceilings.', whyHidden:'The subject matter deflects most visitors. The collection is genuinely superb and the canal house setting extraordinary.', bestTime:'Quiet weekday afternoons', howToGet:'Walk south along Herengracht from Rembrandtplein.', whatToAvoid:'Closed Monday', hiddennessScore:7, category:'Museum / History', interests:['museums','unusual'], lat:52.3664, lng:4.8976, address:'Herengracht 573, Amsterdam', entryPrice:'€12.50', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-westergas', name:'Westergasfabriek', city:'Amsterdam', country:'Netherlands', shortDesc:'Victorian gasworks turned creative campus on the edge of Westerpark', fullDesc:'A late 19th-century gas production complex whose Victorian industrial buildings — gas meters, purification towers, machine halls — have been converted into event spaces, studios and restaurants. The Westerpark surrounding it is excellent for cycling and picnics.', whyHidden:'In the western ring outside the canal belt — not on the standard tourist circuit. The Victorian industrial architecture is some of the finest in Amsterdam.', bestTime:'Summer evenings for outdoor events; Sunday for the park', howToGet:'Tram 10 to Van Limburg Stirumstraat, or bus 21.', whatToAvoid:'Check the events calendar — some buildings close without an event', hiddennessScore:5, category:'Neighbourhood / District', interests:['art','nightlife','photography'], lat:52.3866, lng:4.8701, address:'Pazzanistraat 31, Amsterdam', entryPrice:'Free (events vary)', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-cafe-t-smalle', name:"Café 't Smalle", city:'Amsterdam', country:'Netherlands', shortDesc:'1786 jenever house turned brown café on Egelantiersgracht canal', fullDesc:'One of Amsterdam\'s oldest and most atmospheric brown cafés, established in 1786 as a jenever distillery on Egelantiersgracht. The interior is unchanged — dark wood, pewter, Delft tiles — and the canal-side terrace in summer is one of the finest places to drink in the city.', whyHidden:'On a quiet Jordaan side canal rather than on Prinsengracht or Leidseplein. Easy to miss without local knowledge.', bestTime:'Sunday afternoons; summer terrace evenings', howToGet:'Walk north from Leidseplein through the Jordaan; Egelantiersgracht is between Prinsengracht and Bloemgracht.', whatToAvoid:'Very busy on Friday and Saturday evenings', hiddennessScore:6, category:'Bar / Nightlife', interests:['food','nightlife'], lat:52.3764, lng:4.8831, address:'Egelantiersgracht 12, Amsterdam', entryPrice:'Free entry', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-studio-k', name:'Studio K', city:'Amsterdam', country:'Netherlands', shortDesc:'Local cinema and bar in a converted East Amsterdam factory', fullDesc:'A neighbourhood cultural centre in the Indische Buurt with two cinema screens, a bar, restaurant and regular live music. The programming mixes art-house film with neighbourhood events and the crowd is entirely local students and young professionals from East Amsterdam.', whyHidden:'Deep in the Indische Buurt, East Amsterdam — a neighbourhood tourists never visit. This is where young Amsterdammers actually spend evenings.', bestTime:'Any evening; check the film programme online', howToGet:'Tram 14 to Javaplein, or Metro 54 to Muiderpoort.', whatToAvoid:'Film tickets sell out on weekends — book online', hiddennessScore:8, category:'Underground / Subculture', interests:['art','nightlife'], lat:52.3625, lng:4.9271, address:'Timorplein 62, Amsterdam', entryPrice:'€11 film', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-albert-cuyp-market', name:'Albert Cuyp Market', city:'Amsterdam', country:'Netherlands', shortDesc:'The Netherlands\' longest daily street market in lively De Pijp', fullDesc:'A 260-stall street market stretching the full length of Albert Cuypstraat in De Pijp, operating daily except Sunday. Used by neighbourhood residents for fresh produce, herring, stroopwafels, fabric and household goods. The surrounding De Pijp streets have excellent cafés at non-tourist prices.', whyHidden:'Known to informed visitors but absent from most tours. Functional and local rather than curated for visitors.', bestTime:'Saturday mornings for maximum energy', howToGet:'Tram 16 or 24 to Albert Cuypstraat.', whatToAvoid:'Closed Sundays; some stalls pack up by 4pm', hiddennessScore:4, category:'Market / Street Food', interests:['food','markets'], lat:52.3546, lng:4.8966, address:'Albert Cuypstraat, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-oosterpark', name:'Oosterpark and Indische Buurt', city:'Amsterdam', country:'Netherlands', shortDesc:'Multicultural East Amsterdam neighbourhood around a Victorian park', fullDesc:'A 19th-century park in East Amsterdam surrounded by the city\'s most diverse neighbourhood — Surinamese, Moroccan and Indonesian communities with corresponding food shops, restaurants and cultural life. The park contains a monument to slavery and an extraordinary collection of mature trees.', whyHidden:'East Amsterdam is invisible on most tourist maps. The neighbourhood has the most authentic urban culture in the city.', bestTime:'Sunday afternoons when the park is at its liveliest', howToGet:'Tram 14 to Oosterpark, or Metro 54 to Weesperplein and walk.', whatToAvoid:'Nothing specific — it is a public park and residential area', hiddennessScore:6, category:'Neighbourhood / District', interests:['markets','food','photography'], lat:52.3620, lng:4.9230, address:'Oosterpark, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },

  // ── SECOND PASS ────────────────────────────────────────────────────────────
  { id:'amsterdam-portuguese-synagogue', name:'Portuguese Synagogue (Esnoga)', city:'Amsterdam', country:'Netherlands', shortDesc:'1675 Sephardic synagogue lit entirely by 1,000 candles — no electricity ever installed', fullDesc:'The Portuguese Israelite Synagogue, completed in 1675 and still lit by 1,000 candles and oil lamps exactly as it was built — electricity was never installed. One of the largest synagogues in the world at the time of its construction, built by the Sephardic community expelled from Portugal and Spain. The interior — sand floors, towering brass chandeliers, wooden galleries — is extraordinary and almost unchanged in 350 years.', whyHidden:'Adjacent to the Jewish Historical Museum yet consistently overlooked. The candle-lit interior is one of the most atmospheric religious spaces in Europe.', bestTime:'Friday evening Shabbat service in winter when all 1,000 candles are lit', howToGet:'Tram 9 or 14 to Waterlooplein; walk east past the Jewish Historical Museum.', whatToAvoid:'Closed Saturday (Shabbat); dress modestly', hiddennessScore:5, category:'Spiritual / Ritual', interests:['monuments','photography','museums'], lat:52.3707, lng:4.9017, address:'Mr. Visserplein 3, Amsterdam', entryPrice:'€17', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-verzetsmuseum', name:'Dutch Resistance Museum', city:'Amsterdam', country:'Netherlands', shortDesc:'The most personal WWII museum in Europe — individual stories from the occupation', fullDesc:'The Verzetsmuseum in Plantage documents the Nazi occupation of Amsterdam (1940–1945) through the individual choices made by ordinary people — resistance fighters, collaborators, bystanders. The museum uses personal diaries, photographs and objects to show the human dimension of occupation. The annex follows four children whose fates diverged during the war.', whyHidden:'In Plantage, a quiet neighbourhood tourists don\'t visit. The personal scale of the storytelling is different from any other WWII museum in Europe.', bestTime:'Any weekday morning when it is quiet', howToGet:'Tram 9 or 14 to Plantage Kerklaan; walk to number 61.', whatToAvoid:'Closed Monday', hiddennessScore:5, category:'Museum / History', interests:['museums','monuments'], lat:52.3640, lng:4.9072, address:'Plantage Kerklaan 61, Amsterdam', entryPrice:'€14', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-stedelijk-museum', name:'Stedelijk Museum', city:'Amsterdam', country:'Netherlands', shortDesc:'Dutch and international modern art — the bathtub extension is the best building in the museum quarter', fullDesc:'The municipal museum of modern and contemporary art, with a permanent collection spanning De Stijl, CoBrA, Karel Appel, Mondriaan, Malevich and contemporary video and installation art. The 2012 extension by Benthem Crouwel — nicknamed "the bathtub" for its white porcelain-clad curved form — is one of the finest contemporary buildings in Amsterdam.', whyHidden:'The Rijksmuseum and Van Gogh Museum absorb the Museum Quarter\'s tourist traffic. The Stedelijk\'s collection is more contemporary and equally strong.', bestTime:'Thursday evenings (late opening); weekday mornings', howToGet:'Tram 2, 3, 5 or 12 to Museumplein.', whatToAvoid:'Closed Monday; first Friday of each month has late events', hiddennessScore:4, category:'Gallery / Art', interests:['art','museums','monuments'], lat:52.3580, lng:4.8798, address:'Museumplein 10, Amsterdam', entryPrice:'€22.50', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-beurs-van-berlage', name:'Beurs van Berlage', city:'Amsterdam', country:'Netherlands', shortDesc:'Berlage\'s 1903 stock exchange — the building that launched Dutch modernism', fullDesc:'Hendrik Petrus Berlage\'s 1903 stock exchange is the founding monument of modern Dutch architecture — spare brick rationalism that inspired De Stijl and the Amsterdam School. The main trading hall has original painted murals depicting the history of commerce and is now used as a concert hall. The tower is the finest viewpoint in central Amsterdam.', whyHidden:'Tourists walk past it daily on the way to Dam Square. The interior — freely accessible during events — is extraordinary and entirely overlooked.', bestTime:'During concerts in the main hall; the tower can be climbed on specific open days', howToGet:'Walk south from Centraal Station along Damrak to number 243.', whatToAvoid:'Interior only accessible during events or guided tours — check the programme', hiddennessScore:5, category:'Architecture / Landmark', interests:['monuments','art','photography'], lat:52.3748, lng:4.8985, address:'Damrak 243, Amsterdam', entryPrice:'Free (exterior) / event ticket', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-van-loon-museum', name:'Museum Van Loon', city:'Amsterdam', country:'Netherlands', shortDesc:'The finest canal house interior in Amsterdam — a family still lives upstairs', fullDesc:'A 1672 canal house on Keizersgracht that was home to the Van Loon family from 1884 to the present day. The house is open as a museum while the family occupies the upper floors. The interiors — painted walls, period furniture, the family portrait gallery — are the most complete and authentic of any canal house open to the public.', whyHidden:'The Willet-Holthuysen Museum nearby is more famous. Van Loon is more intimate, more authentic and more surprising.', bestTime:'Weekday mornings when the house is quiet', howToGet:'Walk south along Keizersgracht from Leidseplein to number 672.', whatToAvoid:'Closed Monday and Tuesday', hiddennessScore:6, category:'Museum / History', interests:['museums','monuments','photography'], lat:52.3633, lng:4.8948, address:'Keizersgracht 672, Amsterdam', entryPrice:'€14', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-waterlooplein-market', name:'Waterlooplein Flea Market', city:'Amsterdam', country:'Netherlands', shortDesc:'Amsterdam\'s oldest flea market since 1893 — leather, vinyl, vintage and oddities', fullDesc:'Operating continuously since 1893 except during the German occupation, the Waterlooplein market has stalls selling second-hand clothing, leather jackets, vintage electronics, Dutch ceramics, vinyl records and Amsterdam oddities. The market is used by Amsterdam students and dealers as well as tourists.', whyHidden:'Known but often underestimated — the genuine finds are at the edges and from dealers who arrive early on Saturdays. A morning of serious rummaging rewards.', bestTime:'Monday and Saturday mornings from 9am for the freshest stock', howToGet:'Metro 51/53/54 to Waterlooplein, or tram 9 or 14.', whatToAvoid:'Closed Sunday; some stalls pack up by 3pm', hiddennessScore:4, category:'Market / Street Food', interests:['markets','photography'], lat:52.3682, lng:4.9017, address:'Waterlooplein, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-ij-hallen', name:'IJ-Hallen Flea Market', city:'Amsterdam', country:'Netherlands', shortDesc:'The largest flea market in Europe — once a month at NDSM wharf', fullDesc:'On one Saturday and Sunday per month, the NDSM wharf in Noord hosts the IJ-Hallen market — the largest flea market in Europe with 750+ sellers occupying the vast dry-dock sheds. The range spans vintage furniture, industrial salvage, designer clothing, vinyl, books and genuine antiques. Entry is €5 and the crowd is mixed international.', whyHidden:'Once-monthly schedule requires planning. The scale — enormous industrial sheds full of 750 vendors — is unlike any other flea market in the Netherlands.', bestTime:'Opening time (9am) on market Saturdays — the best pieces go fast', howToGet:'Free NDSM ferry from behind Centraal Station; the market is in the main wharf building.', whatToAvoid:'Check the monthly schedule at ij-hallen.nl — only one weekend per month', hiddennessScore:6, category:'Market / Street Food', interests:['markets','art','photography'], lat:52.4046, lng:4.8975, address:'TT Neveritaweg 15, Amsterdam Noord', entryPrice:'€5', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-rush-hour-records', name:'Rush Hour Records', city:'Amsterdam', country:'Netherlands', shortDesc:'Global institution for electronic music on vinyl — since 1990 in the Grachtengordel', fullDesc:'A record shop on Spuistraat that has been the most important outlet for underground electronic music in the Netherlands since 1990. The shop releases its own label, distributes globally and its staff are among the most knowledgeable record dealers in Europe. The basement stock spans Detroit techno, Chicago house and Dutch electronic music going back to the genre\'s origins.', whyHidden:'On a shopping street tourists walk along but don\'t explore. Known to electronic music communities worldwide but invisible to general visitors.', bestTime:'Any weekday afternoon when staff are available to discuss the stock', howToGet:'Walk from Centraal Station south along Spuistraat to number 116.', whatToAvoid:'Busiest on Friday afternoons when DJs prepare for weekend sets', hiddennessScore:8, category:'Market / Street Food', interests:['markets','art'], lat:52.3740, lng:4.8924, address:'Spuistraat 116, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-paradiso', name:'Paradiso', city:'Amsterdam', country:'Netherlands', shortDesc:'Rock, jazz and dance in a former church since 1968 — the beating heart of Amsterdam nightlife', fullDesc:'A 19th-century church converted into a music venue in 1968 during the hippie movement, now one of Europe\'s most celebrated live music venues. The interior — with original church architecture intact, balconies, a dance floor under the nave — has hosted every major act from The Rolling Stones to Radiohead to contemporary club nights.', whyHidden:'Known to music tourists but often treated as just another venue. The building\'s history — from church to hippie temple to concert hall — and the acoustic quality of the space make it exceptional.', bestTime:'Any concert; the smaller upstairs room hosts the best emerging acts', howToGet:'Tram 1, 2 or 5 to Leidseplein; Paradiso is on Weteringschans.', whatToAvoid:'Tickets sell out for major acts — book online', hiddennessScore:4, category:'Bar / Nightlife', interests:['nightlife','art'], lat:52.3624, lng:4.8819, address:'Weteringschans 6-8, Amsterdam', entryPrice:'€5–30', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-bimhuis', name:'Bimhuis', city:'Amsterdam', country:'Netherlands', shortDesc:'Europe\'s finest jazz venue — cantilevering black box over the IJ waterfront', fullDesc:'A black steel box cantilevering over the IJ waterfront, built in 2005 as the new home of Amsterdam\'s legendary Bimhuis jazz programme (founded 1974). The venue has near-perfect acoustics in an intimate setting of 400 seats. The programme spans experimental jazz to world music to improvised music.', whyHidden:'On the waterfront near Muziekgebouw, slightly outside the tourist circuit. Many jazz fans visiting Amsterdam don\'t know it exists.', bestTime:'Any concert; Tuesday evenings have improvisational open sessions', howToGet:'Walk 10 minutes east from Centraal Station along the IJ waterfront.', whatToAvoid:'Book in advance — popular concerts sell out weeks ahead', hiddennessScore:6, category:'Bar / Nightlife', interests:['nightlife','art'], lat:52.3773, lng:4.9064, address:'Piet Heinkade 3, Amsterdam', entryPrice:'€8–25', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-shelter', name:'Shelter Amsterdam', city:'Amsterdam', country:'Netherlands', shortDesc:'Underground techno club beneath A\'DAM Tower in Amsterdam Noord', fullDesc:'A basement club under the A\'DAM Tower (a former Shell research building) in Amsterdam Noord, with one of the finest sound systems in Europe and a programme of underground techno, house and experimental electronic music. The concrete bunker aesthetic and the ferry crossing from Centraal give the club an exceptional atmosphere.', whyHidden:'Requires the free ferry to Noord and a willingness to commit to a night. Shelter is known to the global underground electronic music community but invisible to most tourists.', bestTime:'Friday and Saturday nights from midnight; door opens at 11pm', howToGet:'Free Buiksloterweg ferry from behind Centraal; walk left from the landing to A\'DAM Tower.', whatToAvoid:'Dress code is strict; respect the door policy', hiddennessScore:7, category:'Bar / Nightlife', interests:['nightlife'], lat:52.3900, lng:4.9022, address:'Overhoeksplein 3, Amsterdam', entryPrice:'€12–18', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-stubbe-haring', name:'Stubbe\'s Haring', city:'Amsterdam', country:'Netherlands', shortDesc:'The best raw herring in Amsterdam — at a cart on Singel since 1973', fullDesc:'A herring stand on the Singel canal near Centraal Station that has been run by the same family since 1973. The new-season herring (Hollandse Nieuwe, available from late May) eaten the traditional way — held by the tail, lowered into the mouth with raw onion — is the defining food experience of Amsterdam.', whyHidden:'Tourists photograph herring carts but most buy from tourist-facing stalls near Centraal. Stubbe\'s, on Singel, is where Amsterdammers buy their herring.', bestTime:'Late May to September for the Hollandse Nieuwe new-season herring; any weekday', howToGet:'Walk from Centraal Station south along Singel to the cart near the Singel flower market.', whatToAvoid:'Closed Sunday; some Mondays in off-season', hiddennessScore:5, category:'Restaurant / Food', interests:['food'], lat:52.3726, lng:4.8924, address:'Singel, Amsterdam (near Torensluis bridge)', entryPrice:'€3–5', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-tempo-doeloe', name:'Tempo Doeloe', city:'Amsterdam', country:'Netherlands', shortDesc:'Amsterdam\'s finest rijsttafel — the Dutch-Indonesian tradition at its most serious', fullDesc:'A restaurant on Utrechtsestraat that has served the Dutch-Indonesian rijsttafel (rice table — 25+ small dishes served with steamed rice) for decades at a level of quality that reflects the genuine depth of Dutch-Indonesian culinary culture. The rijsttafel is a legacy of Dutch colonial rule in Indonesia and Amsterdam\'s large Indonesian community.', whyHidden:'Rijsttafel is one of Amsterdam\'s most important culinary traditions — Dutch colonial history on a table — yet almost no tourist guide covers it seriously.', bestTime:'Dinner Tuesday–Sunday; book a week ahead for weekends', howToGet:'Walk south from Rembrandtplein along Utrechtsestraat to number 75.', whatToAvoid:'Closed Monday; the hot rijsttafel version is significantly spicier than advertised', hiddennessScore:5, category:'Restaurant / Food', interests:['food'], lat:52.3620, lng:4.8964, address:'Utrechtsestraat 75, Amsterdam', entryPrice:'€30–45 per person', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-concerto', name:'Concerto Records', city:'Amsterdam', country:'Netherlands', shortDesc:'Seven rooms of second-hand vinyl and CDs on Utrechtsestraat — the most serious music shop in the Netherlands', fullDesc:'A vinyl shop on Utrechtsestraat occupying several interconnected premises, with over 80,000 records spanning classical, jazz, world music, electronic, rock and spoken word. The classical section alone is extraordinary. Staff are specialists; the adjacent sheet music section serves the city\'s professional musicians.', whyHidden:'On Utrechtsestraat, a street of local independent shops between Rembrandtplein and Frederiksplein. Known to musicians and collectors worldwide but absent from tourist guides.', bestTime:'Any weekday afternoon; Saturday for the highest footfall of local regulars', howToGet:'Walk south from Rembrandtplein along Utrechtsestraat to number 52-54.', whatToAvoid:'The busiest sections are jazz and classical — take time; don\'t rush through', hiddennessScore:6, category:'Market / Street Food', interests:['markets'], lat:52.3611, lng:4.8966, address:'Utrechtsestraat 52-54, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-vondelpark-theatre', name:'Vondelpark Open-Air Theatre', city:'Amsterdam', country:'Netherlands', shortDesc:'Free concerts and theatre all summer in the Vondelpark — entirely local audience', fullDesc:'The Openluchttheater in the Vondelpark presents free concerts, theatre, dance and circus performances every weekend from June to August. The programme covers everything from jazz to children\'s puppet theatre to classical; the audience is entirely Amsterdam residents. One of Europe\'s finest free cultural programmes.', whyHidden:'The Vondelpark is on tourist maps; the free theatre in its centre is not. Many visitors walk through the park and never notice the performances beginning.', bestTime:'Summer weekends from June to late August; check the schedule at openluchttheater.nl', howToGet:'Tram 1, 2, 3, 5 or 12 to Leidseplein; walk into the Vondelpark from the main entrance.', whatToAvoid:'Performances are cancelled in rain', hiddennessScore:4, category:'Park / Green Space', interests:['art','relaxation'], lat:52.3593, lng:4.8726, address:'Vondelpark, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-rijksmuseum-garden', name:'Rijksmuseum Garden', city:'Amsterdam', country:'Netherlands', shortDesc:'The sculpture garden between the museum wings — entirely free, almost entirely unknown', fullDesc:'The Rijksmuseum\'s two wings form a gatehouse through which cyclists and pedestrians pass freely. The gardens flanking the passage contain a sculpture garden with pieces from the museum\'s collection, period garden design and the best view of the museum\'s south facade. Entry to the gardens is free, though most passers-through never look up.', whyHidden:'Cyclists zoom through the museum passage without looking. The garden is technically outside the museum and free — most tourists assume it requires a ticket.', bestTime:'Any morning in spring or summer', howToGet:'Walk or cycle through the Rijksmuseum passage from Museumplein.', whatToAvoid:'Nothing specific — the garden is always open', hiddennessScore:5, category:'Park / Green Space', interests:['art','relaxation','photography'], lat:52.3599, lng:4.8854, address:'Museumstraat, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-reguliersgracht-seven-bridges', name:'Reguliersgracht Seven Bridges', city:'Amsterdam', country:'Netherlands', shortDesc:'A viewpoint on the canal that shows seven identical bridges simultaneously', fullDesc:'Standing on the Thorbeckeplein end of Reguliersgracht, seven identical 17th-century canal bridges are visible simultaneously in a single view — each one framing the next. The view is best at dusk when the bridge lanterns light in sequence. It is one of the most famous views in Amsterdam among Dutch people and largely unknown to tourists.', whyHidden:'Requires knowing exactly which bridge to stand on and at what angle. Most tourists photograph the Keizersgracht bridges and miss this geometrically extraordinary view.', bestTime:'Dusk when the bridge lanterns come on; any still evening for canal reflections', howToGet:'Walk along Keizersgracht to the intersection with Reguliersgracht; stand on the Keizersgracht bridge looking east.', whatToAvoid:'Overcast days reduce the visual impact significantly', hiddennessScore:5, category:'Architecture / Landmark', interests:['photography'], lat:52.3640, lng:4.8933, address:'Reguliersgracht / Keizersgracht, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-westerkerk-tower', name:'Westerkerk Tower (Westertoren)', city:'Amsterdam', country:'Netherlands', shortDesc:'The tallest church tower in Amsterdam — Rembrandt is buried below, Anne Frank heard the bells', fullDesc:'The 85-metre tower of the Westerkerk (1631), Amsterdam\'s tallest church, is climbable on guided tours for one of the finest views in the city. Rembrandt van Rijn is buried somewhere in the church below. Anne Frank\'s hiding place was 500 metres from the tower; she wrote in her diary about hearing the Westerkerk bells.', whyHidden:'The Anne Frank House queue runs past the church but few visitors enter or climb the tower. The tower provides the best view of the Jordaan and the canal ring.', bestTime:'Clear days; April to October (tower open seasonally)', howToGet:'Tram 13 or 17 to Westermarkt.', whatToAvoid:'Tower only open April–October; guided tours at specific times', hiddennessScore:4, category:'Architecture / Landmark', interests:['monuments','photography'], lat:52.3742, lng:4.8839, address:'Prinsengracht 281, Amsterdam', entryPrice:'€10 tower tour', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-borneo-sporenburg', name:'Borneo Sporenburg Eastern Docklands', city:'Amsterdam', country:'Netherlands', shortDesc:'1990s experimental housing on reclaimed docklands — the Netherlands\' most radical residential architecture', fullDesc:'Two artificial peninsulas in the Eastern Docklands where West 8 landscape architects coordinated a radical 1990s housing project: 2,500 houses, each designed by a different architect, producing the most diverse and experimental residential streetscape in Europe. The Whale apartment building and the red Python bridge are iconic; the individual houses are inexhaustible.', whyHidden:'In the Eastern Docklands, east of the city centre, requiring a tram or bus ride. Architects know this as one of the most important late 20th-century residential developments in Europe; almost no tourist visits.', bestTime:'Any day — the architecture is experienced by walking the streets', howToGet:'Bus 22 to KNSM-eiland or Sporenburg.', whatToAvoid:'Nothing specific — residential streets, be respectful', hiddennessScore:8, category:'Architecture / Landmark', interests:['monuments','photography'], lat:52.3698, lng:4.9380, address:'Sporenburg, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-micropia', name:'Artis Micropia', city:'Amsterdam', country:'Netherlands', shortDesc:'The world\'s first museum dedicated entirely to microbes — extraordinary and free for ARTIS members', fullDesc:'The world\'s first museum of microorganisms, opened in 2014 adjacent to the Artis Royal Zoo, with live microbe cultures, scanning electron microscope images and interactive exhibits exploring the invisible world. The "Wall of Microbes" alone — 100 species displayed at near-atomic resolution — is extraordinary.', whyHidden:'Niche subject matter keeps it quiet. The museum is one of the most genuinely educational and visually spectacular in Amsterdam.', bestTime:'Any weekday; the microscope sessions are the best experience', howToGet:'Tram 9 or 14 to Plantage Kerklaan; Micropia is adjacent to the zoo entrance.', whatToAvoid:'Closed Monday', hiddennessScore:7, category:'Museum / History', interests:['museums','unusual'], lat:52.3654, lng:4.9119, address:'Plantage Kerklaan 38-40, Amsterdam', entryPrice:'€17.50', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-poezenboot', name:'De Poezenboot', city:'Amsterdam', country:'Netherlands', shortDesc:'A houseboat on Singel that is home to 50+ rescue cats — since 1966', fullDesc:'A canal houseboat on the Singel operating as a cat sanctuary since 1966, when Henriette van Weelde began rescuing stray cats and housing them on the boat. The current boat holds approximately 50 cats of various ages waiting for adoption. A genuinely unusual Amsterdam institution, staffed by volunteers.', whyHidden:'On the Singel near the flower market, but easy to miss. The cat boat is beloved by Amsterdammers and unknown to most visitors.', bestTime:'Afternoon opening hours (1–3pm daily)', howToGet:'Walk from Centraal Station south along Singel; the boat is moored at number 38.', whatToAvoid:'Limited opening hours — 1–3pm only; respect the cats', hiddennessScore:6, category:'Unusual / Weird', interests:['unusual','relaxation'], lat:52.3752, lng:4.8900, address:'Singel 38g, Amsterdam', entryPrice:'Free (donation)', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-amsterdamse-bos', name:'Amsterdamse Bos', city:'Amsterdam', country:'Netherlands', shortDesc:'Amsterdam\'s enormous park-forest — goat farm, open-air theatre, swimming in the Bosbaan', fullDesc:'A 1,000-hectare forest park built by unemployed workers in the 1930s New Deal era, with a rowing lake (Bosbaan), an organic goat farm open to visitors, an open-air theatre presenting summer concerts, forest cycling paths and swimming areas. The park is Amsterdam\'s outdoor living room.', whyHidden:'Requires a tram or bus to the southern edge of Amsterdam. Most tourists stay in the Vondelpark; Amsterdamse Bos is 20 times larger.', bestTime:'Summer for swimming at the Bosbaan; spring for the blossoming orchard; Sunday morning for cyclists', howToGet:'Tram 25 to Van Nijenrodeweg then walk south; or bus 166 or 170 direct to the park.', whatToAvoid:'Nothing — the park is always accessible and free', hiddennessScore:5, category:'Park / Green Space', interests:['hiking','relaxation','beaches'], lat:52.3154, lng:4.8380, address:'Amsterdamse Bos, Amstelveen', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-ijburg-beach', name:'IJburg Beach (Blijburg)', city:'Amsterdam', country:'Netherlands', shortDesc:'Amsterdam\'s urban beach on a man-made island — the city\'s best-kept summer secret', fullDesc:'A sandy beach on the artificial IJburg island, 20 minutes by tram from Centraal, with a legendary beachclub (Blijburg) operating from April to September. The beach looks across the IJmeer with views of Amsterdam\'s skyline. The crowd is young, local and entirely relaxed — no tourist infrastructure.', whyHidden:'Tourists don\'t associate Amsterdam with beaches. IJburg is a 20-minute tram ride east and the beach is one of the most pleasant summer experiences in any European capital.', bestTime:'Summer afternoons; Sunday morning is the most local', howToGet:'Tram 26 from Centraal Station to Bert Haanstrakade terminus, then walk 5 minutes south.', whatToAvoid:'Beach season is April to September only; November to March the beach is windswept and the club closed', hiddennessScore:6, category:'Beach / Water', interests:['beaches','relaxation'], lat:52.3576, lng:4.9938, address:'Bert Haanstrakade, IJburg, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-felix-meritis', name:'Felix Meritis', city:'Amsterdam', country:'Netherlands', shortDesc:'18th-century Enlightenment society building now housing Amsterdam\'s best debate and art programme', fullDesc:'A 1787 neoclassical building on Keizersgracht built for the Felix Meritis Society — an Enlightenment club for the arts and sciences. The concert hall and lecture rooms now host philosophical debate, contemporary art installations and hybrid performance events. The building\'s history — Napoleon visited, Liszt played here, it became a Communist Party HQ — is extraordinary.', whyHidden:'On Keizersgracht but between tourist attractions. The programming is intellectual and attracts a local audience of academics and artists rather than tourists.', bestTime:'During events — check the programme at felixmeritis.nl', howToGet:'Walk north along Keizersgracht from Leidseplein to number 324.', whatToAvoid:'The building is closed without events; check the programme before visiting', hiddennessScore:7, category:'Gallery / Art', interests:['art','nightlife'], lat:52.3657, lng:4.8820, address:'Keizersgracht 324, Amsterdam', entryPrice:'Varies', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-cobra-museum', name:'CoBrA Museum, Amstelveen', city:'Amsterdam', country:'Netherlands', shortDesc:'The only museum dedicated to the CoBrA avant-garde movement — Karel Appel and Constant', fullDesc:'A museum in Amstelveen dedicated to the CoBrA movement — the postwar avant-garde from Copenhagen, Brussels and Amsterdam (1948–1951) that rejected Surrealism in favour of spontaneous colour and folk imagery. Karel Appel, Constant, Asger Jorn, Corneille. The building is excellent and the collection definitive.', whyHidden:'In Amstelveen, south of Amsterdam, requiring a bus. The CoBrA movement — the founding avant-garde of postwar European art — is poorly known outside the art world.', bestTime:'Any weekday morning', howToGet:'Bus 170 from Amsterdam Centraal to Amstelveen, or tram 25 south.', whatToAvoid:'Closed Monday', hiddennessScore:7, category:'Gallery / Art', interests:['art','museums'], lat:52.3041, lng:4.8611, address:'Sandbergplein 1-3, Amstelveen', entryPrice:'€16', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-tolhuistuin', name:'Tolhuistuin', city:'Amsterdam', country:'Netherlands', shortDesc:'Shell\'s former staff canteen turned outdoor concert and culture venue in Amsterdam Noord', fullDesc:'The former Shell canteen and garden in Amsterdam Noord (Shell had its global HQ here), converted into an open-air music and culture venue with a large garden, two indoor stages and some of the most interesting programming in Amsterdam. The ferry crossing gives the venue a special atmosphere.', whyHidden:'Requires the free Buiksloterweg ferry — enough friction to keep it authentic. One of the best live music venues in Amsterdam.', bestTime:'Summer outdoor concerts; check tolhuistuin.nl for the programme', howToGet:'Free Buiksloterweg ferry from behind Centraal Station; Tolhuistuin is 2 minutes from the landing.', whatToAvoid:'Indoor venue closed between events', hiddennessScore:6, category:'Bar / Nightlife', interests:['nightlife','art'], lat:52.3870, lng:4.9020, address:'IJpromenade 2, Amsterdam', entryPrice:'Free (events vary)', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-hofjes-circuit', name:'Jordan Hofjes Circuit', city:'Amsterdam', country:'Netherlands', shortDesc:'18 hidden almshouse courtyards throughout the Jordaan — the city\'s most secret spaces', fullDesc:'The Jordaan district contains 18 hofjes — enclosed almshouse courtyards founded between the 17th and 19th centuries, accessible through unmarked doors in canal-house facades. Beyond Hofje van Brienen, the circuit includes Karthuizerhofje (largest, founded 1650), Bossche Hofje, Raepenhofje and others. Each has its own garden, pump and atmosphere.', whyHidden:'No tourist map shows all 18; many have completely unmarked entrances. The complete hofje circuit requires a dedicated morning with a detailed local map.', bestTime:'Weekday mornings in spring and summer; the larger hofjes are most accessible', howToGet:'Start at Karthuizerhofje (Karthuizerstraat 89-171) and use a hofjes map from the tourist office.', whatToAvoid:'Residents live in all hofjes — be quiet and respectful', hiddennessScore:7, category:'Architecture / Landmark', interests:['monuments','photography','relaxation'], lat:52.3765, lng:4.8822, address:'Karthuizerstraat, Jordaan, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-athenaeum-bookshop', name:'Athenaeum Boekhandel', city:'Amsterdam', country:'Netherlands', shortDesc:'Amsterdam\'s finest bookshop on Spui — the city\'s intellectual heart since 1966', fullDesc:'An independent bookshop on the Spui square operating since 1966, with the finest selection of English and Dutch-language literature, art books, philosophy and travel writing in Amsterdam. The adjacent newsagent stocks every major international newspaper and magazine. The Spui square itself hosts a book and antique market every Friday and Saturday.', whyHidden:'The bookshop is on the tourist route near the Begijnhof but tourists walk past without entering. The English-language selection is among the best in Europe.', bestTime:'Any weekday morning; Friday–Saturday for the Spui book market outside', howToGet:'Walk to Spui square from the Rokin or the Begijnhof.', whatToAvoid:'Nothing specific', hiddennessScore:4, category:'Market / Street Food', interests:['markets','art'], lat:52.3693, lng:4.8917, address:'Spui 14-16, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-bloemenmarkt', name:'Bloemenmarkt at Opening', city:'Amsterdam', country:'Netherlands', shortDesc:'The world\'s only floating flower market — arrive at 9am before the bulb tourists', fullDesc:'The Bloemenmarkt on the Singel has operated on floating barges since 1862. In the first hour after opening, before the tour groups arrive, the stalls are arranged with extraordinary precision — cut flowers, tulip bulbs, seeds, plant cuttings. The market is genuine: the bulbs sold here go to Dutch gardens across the country.', whyHidden:'Known but visited at the wrong time. The 9am version — before tour buses — has the full flower density and the sellers unpacking fresh stock.', bestTime:'Tuesday–Saturday from 9am; avoid Saturday afternoons', howToGet:'Tram 1, 2 or 5 to Koningsplein.', whatToAvoid:'Closed Sunday; most interesting before 11am', hiddennessScore:3, category:'Market / Street Food', interests:['markets','photography'], lat:52.3669, lng:4.8924, address:'Singel, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-surinamese-bijlmer', name:'Bijlmer Surinamese Food', city:'Amsterdam', country:'Netherlands', shortDesc:'Amsterdam\'s Surinamese community serves the best roti and pom in the Netherlands', fullDesc:'The Bijlmer neighbourhood in Southeast Amsterdam has the largest Surinamese community in the Netherlands, with a concentrated street of Surinamese restaurants serving dishes unavailable elsewhere in Europe: pom (a taro and chicken bake), roti with masala potato, baka bana (fried banana) and bara (split pea fritters). The food reflects Suriname\'s unique African-Indian-Dutch-Indonesian mixture.', whyHidden:'Requires the Metro to Amsterdam Zuidoost — a journey almost no tourist makes. The most interesting and culturally specific cuisine in Amsterdam is entirely outside the tourist circuit.', bestTime:'Saturday lunchtime when the community restaurants are busiest', howToGet:'Metro 50, 53 or 54 to Amsterdam Bijlmer ArenA, walk to the market streets.', whatToAvoid:'Some restaurants closed early in the week', hiddennessScore:8, category:'Restaurant / Food', interests:['food','markets'], lat:52.3120, lng:4.9542, address:'Bijlmer, Amsterdam Zuidoost', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-hollandsche-schouwburg', name:'Hollandsche Schouwburg', city:'Amsterdam', country:'Netherlands', shortDesc:'The theatre where Amsterdam\'s Jews were assembled before deportation — now a memorial', fullDesc:'A former theatre in Plantage used by the Nazis as the main assembly point for Amsterdam\'s Jewish residents before deportation to Westerbork and then Sobibor and Auschwitz. The roofless theatre ruin — the stage wall preserved, a memorial flame burning in the stalls — contains the names of 102,000 Dutch Jewish victims. One of the most affecting memorial spaces in Europe.', whyHidden:'In Plantage, a quiet neighbourhood. The Anne Frank House absorbs the Holocaust memorial tourism; this site — where the deportations physically happened — is equally important and almost empty.', bestTime:'Any weekday morning when the space can be absorbed quietly', howToGet:'Tram 9 or 14 to Plantage Middenlaan; the theatre is at number 24.', whatToAvoid:'Nothing specific — respectful behaviour throughout', hiddennessScore:5, category:'Museum / History', interests:['museums','monuments'], lat:52.3641, lng:4.9103, address:'Plantage Middenlaan 24, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-bos-en-lommer', name:'Bos en Lommer', city:'Amsterdam', country:'Netherlands', shortDesc:'Amsterdam\'s most authentically multicultural neighbourhood — Moroccan bakeries and Dutch art deco', fullDesc:'A neighbourhood in Nieuw-West with large Moroccan, Turkish and Surinamese communities alongside original Dutch Art Deco worker housing from the 1920s–30s. The Mercatorplein square is a 1934 Berlage design. The Moroccan bakeries and butchers provide the best bread in Amsterdam and the neighbourhood market is entirely non-tourist.', whyHidden:'In Nieuw-West, entirely off tourist maps. The interwar architectural quality and the North African food culture make for an extraordinary and overlooked combination.', bestTime:'Saturday morning for the market and bakeries', howToGet:'Tram 7 to Jan van Galenstraat; walk to Mercatorplein.', whatToAvoid:'Nothing specific', hiddennessScore:8, category:'Neighbourhood / District', interests:['food','markets','photography'], lat:52.3810, lng:4.8520, address:'Mercatorplein, Bos en Lommer, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-jewish-museum', name:'Jewish Historical Museum', city:'Amsterdam', country:'Netherlands', shortDesc:'Four interconnected 17th-century synagogues — the most important Jewish heritage site in Western Europe', fullDesc:'Four interconnected Ashkenazi synagogues built between 1670 and 1752, surviving the war because the German occupiers used them as storage rather than destroying them. Now a museum of Dutch Jewish history and culture, with the original synagogue interiors — galleries, bimot, ark — intact and used for events.', whyHidden:'Adjacent to the Portuguese Synagogue and often bypassed for it. The Ashkenazi complex is architecturally and historically significant and has different emphasis in its storytelling.', bestTime:'Any weekday morning', howToGet:'Tram 9 or 14 to Waterlooplein; the museum is on Nieuwe Amstelstraat 1.', whatToAvoid:'Closed Saturday and Jewish holidays', hiddennessScore:4, category:'Museum / History', interests:['museums','monuments','art'], lat:52.3697, lng:4.9013, address:'Nieuwe Amstelstraat 1, Amsterdam', entryPrice:'€17', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-prinsengracht-concert', name:'Prinsengracht Concert', city:'Amsterdam', country:'Netherlands', shortDesc:'Free classical concert on the Prinsengracht canal — boats, bridges and 10,000 listeners every August', fullDesc:'On a Saturday in mid-August each year, a free classical concert takes place on a floating stage on the Prinsengracht, with the audience filling the canal bridges, houseboats and canal walls for a kilometre. The combination of classical music, canal geography and 10,000 Amsterdammers creates an entirely unique atmosphere.', whyHidden:'Once a year in August; requires being in Amsterdam at the right moment and knowing to look for it. One of the most beautiful free cultural events in Europe.', bestTime:'The specific Saturday in mid-August; arrive early to secure a bridge position', howToGet:'Walk to Prinsengracht in the Jordaan (around Pulitzer Hotel area) on the concert Saturday.', whatToAvoid:'Arrive at least 2 hours early — bridge positions fill very fast', hiddennessScore:7, category:'Park / Green Space', interests:['art','relaxation'], lat:52.3680, lng:4.8836, address:'Prinsengracht, Jordaan, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-de-pijp-wine', name:'De Pijp Natural Wine Bars', city:'Amsterdam', country:'Netherlands', shortDesc:'Amsterdam\'s most vibrant neighbourhood has the city\'s best wine bar scene', fullDesc:'The De Pijp neighbourhood, south of the Rijksmuseum, has developed the most interesting natural wine bar culture in Amsterdam — Bar Bukowski, Bar Fisk, Brouwerij Troost De Pijp and several others occupy former Albert Cuypstraat-adjacent premises. The neighbourhood crowd is young, Dutch and entirely local.', whyHidden:'Tourists visit the Albert Cuyp market in De Pijp by day but don\'t return in the evenings. The wine bar scene is entirely unmarked on tourist maps.', bestTime:'Any evening from 6pm; Thursday–Saturday are the liveliest', howToGet:'Tram 3, 12 or 24 to Stadhouderskade; walk east into De Pijp.', whatToAvoid:'Nothing specific', hiddennessScore:5, category:'Bar / Nightlife', interests:['nightlife','food'], lat:52.3541, lng:4.8950, address:'De Pijp, Amsterdam', entryPrice:'Free entry', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-sarphatipark', name:'Sarphatipark', city:'Amsterdam', country:'Netherlands', shortDesc:'De Pijp\'s private garden — Victorian ornamental park, no tourists', fullDesc:'A small Victorian ornamental park in the heart of De Pijp, named after Samuel Sarphati who planned the neighbourhood. The park has a central pond with ornate 19th-century bridge, mature London planes, a bandstand and a local café kiosk. Used daily by De Pijp residents as their front garden.', whyHidden:'One block from the Albert Cuyp market yet consistently overlooked. The park is the social heart of De Pijp for the people who actually live there.', bestTime:'Any weekend morning; summer evenings', howToGet:'Tram 3, 12 or 24 to Stadhouderskade; walk east into De Pijp to Sarphatipark.', whatToAvoid:'Nothing specific', hiddennessScore:5, category:'Park / Green Space', interests:['relaxation','photography'], lat:52.3541, lng:4.8950, address:'Sarphatipark, Amsterdam', entryPrice:'Free', photo:'1576924542371-f4f5c9c5e06d' },
  { id:'amsterdam-silodam', name:'Silodam Apartment Building', city:'Amsterdam', country:'Netherlands', shortDesc:'MVRDV\'s 2002 apartment silo on the IJ — the most interesting building in Amsterdam', fullDesc:'A 2002 residential building by MVRDV on the IJ waterfront west of Centraal, designed as a vertical neighbourhood with 157 apartments each of a different type — studios, terraced houses, maisonettes — stacked in a grid and colour-coded on the facade. The building is considered one of the most significant works of Dutch architecture of its decade.', whyHidden:'On the IJ waterfront 10 minutes\' walk west of Centraal, but off the tourist walking routes. Architects and architecture students visit from across Europe; tourists almost never find it.', bestTime:'Any day — the exterior is always accessible from the water side', howToGet:'Walk west from Centraal Station along the IJ waterfront past Ijdock.', whatToAvoid:'The building is private residential — exterior only', hiddennessScore:7, category:'Architecture / Landmark', interests:['monuments','photography'], lat:52.3879, lng:4.8806, address:'Silodam 1, Amsterdam', entryPrice:'Free (exterior)', photo:'1576924542371-f4f5c9c5e06d' },
  { id: 'amsterdam-czar-peter-house', name: 'Czaar Peterbuurt and Peter the Great House', city: 'Amsterdam', country: 'Netherlands', shortDesc: 'Tsar Peter worked here incognito in 1697 — the smallest historic building in Amsterdam', fullDesc: 'The Czaar Peterhuisje in the Czaar Peterbuurt neighbourhood is a tiny building where Tsar Peter the Great lived while working incognito as a carpenter at the VOC shipyard in 1697 — learning shipbuilding techniques. The house is preserved and occasionally open; the surrounding neighbourhood was named after him and retains a quiet, non-tourist character.', whyHidden: 'In the eastern Czaar Peterbuurt neighbourhood, far from the canal belt tourist zone. The neighbourhood has good Indonesian and Surinamese restaurants in addition to the historical connection.', bestTime: 'Any weekday; the Czaar Peterbuurt neighbourhood is particularly good Saturday morning for the local market', howToGet: 'Tram 7, 14 or 19 to Czaar Peterstraat.', whatToAvoid: 'The interior of the Czaar Peterhuisje is rarely open — check at the Amsterdam Museum for opening times', hiddennessScore: 7, category: 'History', interests: ['history', 'unusual', 'neighbourhood'], lat: 52.3680, lng: 4.9380, address: 'Czaar Peterhuisje, Wittenburgergracht 7, Amsterdam', entryPrice: 'Free (exterior)', photo: '1467218504634-7f7519dc8b85' },

  { id: 'amsterdam-national-maritime-museum', name: 'Scheepvaartmuseum Amsterdam', city: 'Amsterdam', country: 'Netherlands', shortDesc: 'The Netherlands\' maritime history in a 1656 naval storehouse — with a full-size replica VOC ship', fullDesc: 'The Scheepvaartmuseum (Maritime Museum) occupies the 1656 Amsterdam Admiralty storehouse on the Oosterdok. The collection traces Dutch maritime history from the Golden Age to the present with extraordinary accuracy: maps, instruments, ship models, and the full-scale replica of the VOC sailing ship Amsterdam in the harbour behind, which can be boarded and explored.', whyHidden: 'The Rijksmuseum and Anne Frank House attract almost all tourist attention. The Maritime Museum — in a beautiful 17th-century building with a full-size replica sailing ship — is far less crowded.', bestTime: 'Any weekday morning; the VOC ship is most atmospheric in grey weather', howToGet: 'Bus 22 or 48 to Kattenburgerplein.', whatToAvoid: 'Closed Mondays', hiddennessScore: 5, category: 'History', interests: ['history', 'architecture', 'unusual'], lat: 52.3738, lng: 4.9165, address: 'Kattenburgerplein 1, Amsterdam', entryPrice: '€16.50', photo: '1467218504634-7f7519dc8b85' },

  { id: 'amsterdam-vondelpark-rose-garden', name: 'Vondelpark Rose Garden and Pavilion', city: 'Amsterdam', country: 'Netherlands', shortDesc: 'Amsterdam\'s most used park at its most beautiful — the rose garden is extraordinary in June', fullDesc: 'Vondelpark is Amsterdam\'s famous city park, but its rose garden — in the south of the park, near the Film Museum — blooms in June with over 70 varieties of roses. The adjacent Vondelpark Pavilion (1874) has a beautiful terrace. The park has free open-air concerts at the Vondelpark Openluchttheater from June to August on summer evenings.', whyHidden: 'The park is known but the rose garden section is undervisited. The free open-air theatre events are the best free entertainment in Amsterdam in summer.', bestTime: 'June for the rose garden; summer evenings for the free outdoor concerts', howToGet: 'Tram 1, 3 or 12 to Vondelpark.', whatToAvoid: 'The park is very crowded on sunny summer weekends — weekday mornings are the best', hiddennessScore: 3, category: 'Park', interests: ['park', 'art', 'nature'], lat: 52.3574, lng: 4.8685, address: 'Vondelpark, Amsterdam', entryPrice: 'Free', photo: '1495435898-33d8e1a25032' },

  { id: 'amsterdam-amsterdam-school-plan-south', name: 'Amsterdam School Plan Zuid Architecture Walk', city: 'Amsterdam', country: 'Netherlands', shortDesc: 'The Amsterdam School\'s expressionist social housing — brick sculptures, not just buildings', fullDesc: 'Plan Zuid (the South Plan), designed by H.P. Berlage and built out in the Amsterdam School style from 1917–1940, contains the most concentrated expressionist social housing in the world — Michel de Klerk\'s Het Schip block, Piet Kramer\'s bridges, and hundreds of apartment buildings with sculpted brick facades, unusual corners and tower elements. This was the world\'s most ambitious social housing programme.', whyHidden: 'In the south of Amsterdam, in an entirely residential area. The Amsterdam School of architecture has no international equivalent and the Plan Zuid blocks are its greatest achievements.', bestTime: 'Any clear morning; the brick facades are extraordinary in raking light', howToGet: 'Tram 3, 5 or 25 to De Pijp or Museum Quarter.', whatToAvoid: 'The Het Schip museum (the finest single Amsterdam School building) requires a separate visit to the Spaarndammerbuurt', hiddennessScore: 7, category: 'Architecture', interests: ['architecture', 'history', 'neighbourhood'], lat: 52.3477, lng: 4.8890, address: 'Churchillaan, Plan Zuid, Amsterdam', entryPrice: 'Free', photo: '1528727548-8e814d0cb3a2' },

  { id: 'amsterdam-tropenmuseum', name: 'Tropenmuseum (Museum of the Tropics)', city: 'Amsterdam', country: 'Netherlands', shortDesc: 'The Dutch colonial collection — an honest reckoning with the empire and an extraordinary building', fullDesc: 'The Tropenmuseum in a magnificent 1926 building houses the Dutch anthropological collection from the colonial period — Indonesian, Caribbean, African and South Asian material culture. The museum has engaged seriously with its colonial legacy and the displays address the history critically. The building\'s interior atrium is one of the finest in Amsterdam.', whyHidden: 'In Oost (east Amsterdam), not near the canal belt. The building alone — with its huge atrium and gallery levels — is exceptional.', bestTime: 'Any weekday morning', howToGet: 'Tram 7, 14 or 19 to Alexanderplein.', whatToAvoid: 'Closed Mondays', hiddennessScore: 5, category: 'Museum', interests: ['history', 'art', 'architecture'], lat: 52.3567, lng: 4.9192, address: 'Linnaeusstraat 2, Amsterdam', entryPrice: '€15', photo: '1467218504634-7f7519dc8b85' },

  { id: 'amsterdam-waterlooplein-flea-market', name: 'Waterlooplein Flea Market', city: 'Amsterdam', country: 'Netherlands', shortDesc: 'Amsterdam\'s oldest daily flea market — the Jewish quarter\'s original market since 1893', fullDesc: 'Waterlooplein flea market has operated since 1893 as the market of Amsterdam\'s Jewish quarter and trades every day except Sunday. The current market has second-hand clothes, vintage cameras, old Dutch books and prints, bicycle parts and household goods. It is Amsterdam\'s most authentic market, adjacent to the Jewish Historical Museum.', whyHidden: 'Known but undervisited because it appears scruffier than the tourist-facing markets. The Dutch vintage prints and books section has excellent material.', bestTime: 'Any weekday morning from 9am', howToGet: 'Metro 51/53/54 to Waterlooplein; tram 9 or 14.', whatToAvoid: 'Closed Sunday; the market is at its fullest on weekday mornings', hiddennessScore: 4, category: 'Market', interests: ['market', 'history', 'neighbourhood'], lat: 52.3676, lng: 4.9028, address: 'Waterlooplein, Amsterdam', entryPrice: 'Free', photo: '1555041469-db61523df9a4' },

  { id: 'amsterdam-westergas-terrain', name: 'Westergasfabriek — Former Gas Works', city: 'Amsterdam', country: 'Netherlands', shortDesc: '1890s gas works converted to Amsterdam\'s most interesting cultural venue', fullDesc: 'The Westergasfabriek is a complex of 1890s gas-manufacturing buildings converted to a cultural park — concert venues, film studios, weekly organic food market, and a large park. The original gasometer, purification towers and machinery halls give the complex an extraordinary industrial character now entirely absent from the city centre.', whyHidden: 'West of the Jordaan, in a non-tourist district. The Sunday organic market and the weekend events programme make it the most interesting non-central cultural complex in Amsterdam.', bestTime: 'Sunday morning for the organic market; Friday evenings for the events programme', howToGet: 'Tram 10 or bus 18 to Haarlemmerplein; walk west.', whatToAvoid: 'The complex is only active when events are programmed; check the weekly calendar', hiddennessScore: 5, category: 'Architecture', interests: ['architecture', 'neighbourhood', 'market'], lat: 52.3858, lng: 4.8712, address: 'Pazzanistraat 37, Amsterdam', entryPrice: 'Free (events vary)', photo: '1504966191903-6f9e6c4b8c4a' },

  { id: 'amsterdam-ij-tunnel-cycle', name: 'IJ Harbour Ferry at Night', city: 'Amsterdam', country: 'Netherlands', shortDesc: 'The free 24-hour ferry across the IJ — Amsterdam Oost and Noord by night', fullDesc: 'The Buiksloterweg, NDSM and IJplein ferries cross the IJ harbour from behind Amsterdam Centraal and run 24 hours a day, completely free. At night, the crossing — with the city lights reflected in the IJ, the vast harbour cranes and the NDSM wharf\'s industrial buildings on the far bank — is one of the most atmospheric experiences in Amsterdam.', whyHidden: 'The ferries are essential transport for locals cycling to Noord but tourists almost never take them. The crossing takes 2 minutes and gives the finest view of Amsterdam\'s water-city character.', bestTime: 'Evening from 8pm when the city lights reflect in the water; the NDSM ferry is most atmospheric', howToGet: 'Walk behind Amsterdam Centraal to the free ferry terminal (separate from the private tourist boats).', whatToAvoid: 'The paid tourist ferries depart from the front of Centraal Station; the free public ferries are behind', hiddennessScore: 4, category: 'Unusual', interests: ['unusual', 'neighbourhood', 'neighbourhood'], lat: 52.3802, lng: 4.9072, address: 'IJ Ferry Terminal, Amsterdam Noord', entryPrice: 'Free', photo: '1544621740-813eda3ef16e' },

  { id: 'amsterdam-amsterdam-north-culture', name: 'Amsterdam Noord — NDSM Wharf', city: 'Amsterdam', country: 'Netherlands', shortDesc: 'Former shipyard converted to Europe\'s largest creative hub', fullDesc: 'NDSM Wharf in Amsterdam Noord is a former shipyard converted to an enormous creative hub — artists\' studios, independent cinema, events venues, the Pllek restaurant in shipping containers, street art on a massive scale, and the IJ Hallen flea market (one of Europe\'s largest, held monthly). The free ferry from Centraal takes 15 minutes.', whyHidden: 'The free ferry puts Noord off many tourist itineraries despite it being 15 minutes from the centre. The scale of the NDSM industrial complex — a full shipyard with original cranes — is extraordinary.', bestTime: 'Any weekend for the arts and food scene; the IJ Hallen market runs on specific weekends (check dates)', howToGet: 'Free NDSM ferry from behind Amsterdam Centraal (25 minutes).', whatToAvoid: 'The NDSM wharf is active mainly on weekends; weekday daytime has fewer businesses open', hiddennessScore: 5, category: 'Art', interests: ['art', 'neighbourhood', 'unusual'], lat: 52.3989, lng: 4.8985, address: 'TT Neveritaweg 15, Amsterdam Noord', entryPrice: 'Free', photo: '1587974928442-77dc3e0dba72' },

  { id: 'amsterdam-de-pijp-neighborhood', name: 'De Pijp Neighbourhood Saturday Morning', city: 'Amsterdam', country: 'Netherlands', shortDesc: 'Amsterdam\'s most diverse neighbourhood — Albert Cuyp market and the best breakfast', fullDesc: 'De Pijp (The Pipe) is Amsterdam\'s 19th-century working-class district, now the most culturally diverse neighbourhood in the Netherlands. Albert Cuyp Market runs daily (the longest daily market in the Netherlands) with Dutch herring, stroopwafels, Surinamese roti, Moroccan spices and everything else. The neighbourhood has excellent independent cafés for Saturday breakfast.', whyHidden: 'De Pijp is known for the Albert Cuyp Market. The neighbourhood around and beyond the market — the Saturday morning culture of the side streets — is less documented.', bestTime: 'Saturday morning from 9am for the full combination of market and neighbourhood café culture', howToGet: 'Tram 3, 16 or 24 to Albert Cuyp.', whatToAvoid: 'Saturday afternoons are very crowded; Sunday the market is closed but the neighbourhood remains active', hiddennessScore: 3, category: 'Neighbourhood', interests: ['neighbourhood', 'market', 'food'], lat: 52.3521, lng: 4.8956, address: 'Albert Cuypstraat, De Pijp, Amsterdam', entryPrice: 'Free', photo: '1555041469-db61523df9a4' },
];
